// Whitelist of allowed commands for security
object CommandWhitelist {
  val allowedCommands: Set[String] = Set(
    "ls", "df", "du", "uptime", "whoami", "hostname",
    "ps", "top", "free", "uname", "date", "cat",
    "systemctl", "journalctl", "docker", "kubectl",
    "ping", "dig", "nslookup", "curl", "netstat", "ss"
  )

  def isAllowed(command: String): Boolean = allowedCommands.contains(command)
}

// Input validation
object InputValidator {
  // Reject arguments containing shell metacharacters
  private val dangerousPatterns = List(
    ";", "&&", "||", "|", "`", "$(", "${",
    ">", "<", ">>", "<<", "\n", "\r", "&"
  )

  def validateArgument(arg: String): Either[String, String] = {
    if (arg.isEmpty) Left("Empty argument not allowed")
    else if (dangerousPatterns.exists(arg.contains)) Left(s"Argument contains forbidden characters: $arg")
    else if (arg.contains("..") && (arg.contains("/") || arg.contains("\\"))) Left(s"Path traversal detected: $arg")
    else Right(arg)
  }

  def validateArguments(args: List[String]): Either[String, List[String]] = {
    val results = args.map(validateArgument)
    val errors = results.collect { case Left(err) => err }
    if (errors.nonEmpty) Left(errors.mkString(", "))
    else Right(results.collect { case Right(arg) => arg })
  }
}

// Secure command executor — uses Process with argument lists (NOT string interpolation)
object SecureCommandExecutor {

  def execute(command: String, arguments: List[String], timeoutSeconds: Int = 30): CommandResponse = {
    // Step 1: Check command whitelist
    if (!CommandWhitelist.isAllowed(command)) {
      return CommandResponse(
        exitCode = -1,
        stdout = "",
        stderr = s"Command '$command' is not in the allowed commands whitelist. Allowed: ${CommandWhitelist.allowedCommands.mkString(", ")}",
        success = false
      )
    }

    // Step 2: Validate arguments
    InputValidator.validateArguments(arguments) match {
      case Left(error) =>
        return CommandResponse(
          exitCode = -1,
          stdout = "",
          stderr = s"Invalid arguments: $error",
          success = false
        )
      case Right(_) => // proceed
    }

    // Step 3: Execute using Process with a sequence of arguments (SAFE — no shell interpolation)
    // This passes each argument separately to the OS, preventing injection
    val cmdSeq: Seq[String] = command +: arguments

    val stdoutBuilder = new StringBuilder
    val stderrBuilder = new StringBuilder

    val processLogger = ProcessLogger(
      (out: String) => stdoutBuilder.append(out).append("\n"),
      (err: String) => stderrBuilder.append(err).append("\n")
    )

    Try {
      val process = Process(cmdSeq)
      val exitCode = process.!(processLogger)
      exitCode
    } match {
      case Success(exitCode) =>
        CommandResponse(
          exitCode = exitCode,
          stdout = stdoutBuilder.toString().trim,
          stderr = stderrBuilder.toString().trim,
          success = exitCode == 0
        )
      case Failure(exception) =>
        CommandResponse(
          exitCode = -1,
          stdout = "",
          stderr = s"Execution failed: ${exception.getMessage}",
          success = false
        )
    }
  }
}

